    if conditions:
        base_query += " WHERE " + " AND ".join(conditions)

    allowed_sort_fields = {'name', 'price', 'rating', 'created_at', 'stock_quantity', 'id', 'category', 'brand'}
    sort_by = params.get('sort_by', 'id')
